static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;
    const gert::StorageShape *x_shape = context->GetInputShape(0);
    const gert::StorageShape *h0_shape = context->GetInputShape(1);
    const gert::StorageShape *w_h2o_shape = context->GetInputShape(4);

    // Use logical origin shapes
    auto x_origin = x_shape->GetOriginShape();
    auto h0_origin = h0_shape->GetOriginShape();
    auto w_h2o_origin = w_h2o_shape->GetOriginShape();

    uint32_t T = static_cast<uint32_t>(x_origin.GetDim(0));
    uint32_t B = static_cast<uint32_t>(x_origin.GetDim(1));
    uint32_t I = static_cast<uint32_t>(x_origin.GetDim(2));
    uint32_t H = static_cast<uint32_t>(h0_origin.GetDim(1));
    uint32_t O = static_cast<uint32_t>(w_h2o_origin.GetDim(0));
    uint32_t K = I + H;

    uint32_t totalLength = T * B * O;
    uint32_t tileLength = B * I;  // slice per time step for one batch
    uint32_t blockDim = B;
    if (blockDim > 24) blockDim = 24;
    if (blockDim < 1) blockDim = 1;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLength);
    tiling.set_blockDim(blockDim);
    tiling.set_T(T);
    tiling.set_B(B);
    tiling.set_I(I);
    tiling.set_H(H);
    tiling.set_O(O);
    tiling.set_K(K);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

